const test_n = '0jxtT5vvyFbDXAMk0eQfMLYvGI5uYj9d3tktHIvqNK3N2ck7hueoMpOamUSdeoWZucXybJ1BnR-vzc0nRTS12B8tdzWlMTL8qKc-JTdnomOey8E1DfLz5bNcTtZhwQ1AnEYkS8PSY_xqQad-m-FMYH2PDWkWZMsPUIUS1-cKzCTmI-k4UGKFkUizXY56AcEAwPijNRbg_5mOtEjRnViXzW1XsrcLLR9mmvI0NRmn__90lhe37KBSBSbVU9hnaYXZwToXlJu9Wj6j4O2LRRjxIEW-urr2F6-KpTEBB57BJD4Th2-tYEhBfTVHFX0TXxogFymQVfIqzKz3G47FNyEFnw'
const test_e = 'AQAB'

fn test_verify_jwt_rs256_accepts_a_genuine_signature() {
	ok := verify_jwt_rs256(test_jwt, test_n, test_e) or { panic('unexpected error: ${err}') }
	assert ok
}

fn test_verify_jwt_rs256_rejects_a_forged_payload() {
	ok := verify_jwt_rs256(tampered_jwt, test_n, test_e) or { panic('unexpected error: ${err}') }
	assert !ok
}

fn test_verify_jwt_rs256_rejects_wrong_key() {
	// A well formed but different RSA key (same e, one modulus digit
	// changed). Must be rejected, not accidentally accepted.
	wrong_n := '1jxtT5vvyFbDXAMk0eQfMLYvGI5uYj9d3tktHIvqNK3N2ck7hueoMpOamUSdeoWZucXybJ1BnR-vzc0nRTS12B8tdzWlMTL8qKc-JTdnomOey8E1DfLz5bNcTtZhwQ1AnEYkS8PSY_xqQad-m-FMYH2PDWkWZMsPUIUS1-cKzCTmI-k4UGKFkUizXY56AcEAwPijNRbg_5mOtEjRnViXzW1XsrcLLR9mmvI0NRmn__90lhe37KBSBSbVU9hnaYXZwToXlJu9Wj6j4O2LRRjxIEW-urr2F6-KpTEBB57BJD4Th2-tYEhBfTVHFX0TXxogFymQVfIqzKz3G47FNyEFnw'
	ok := verify_jwt_rs256(test_jwt, wrong_n, test_e) or { panic('unexpected error: ${err}') }
	assert !ok
}

fn test_verify_jwt_rs256_rejects_malformed_token() {
	if _ := verify_jwt_rs256('not-a-jwt', test_n, test_e) {
		assert false
	}
}
